"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport, type UIMessage } from "ai";
import { useState } from "react";

interface UseCustomerMemoryChatWithFactoryOptions<TMessage extends UIMessage> {
  createChat: () => Chat<TMessage>;
}

export function useCustomerMemoryChat<TMessage extends UIMessage = UIMessage>(
  options: UseCustomerMemoryChatWithFactoryOptions<TMessage>
) {
  const [chat] = useState(() => options.createChat());
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    chat,
    hasMessages,
    isBusy,
  };
}

"use client";

import { Chat } from "@ai-sdk/react";
import { type ChatStatus, DefaultChatTransport, type UIMessage } from "ai";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { customerMemoryProfiles } from "@/lib/customer-memory-agent/customer-profiles";
import type { CustomerMemorySessionData } from "@/lib/customer-memory-agent/session-data";
import {
  buildCustomerMemorySessionViewState,
  getLatestCustomerMemoryPrompt,
  removeEmptyCustomerMemoryAssistantMessages,
} from "./customer-memory-session";
import { useCustomerMemoryChat } from "./use-customer-memory-chat";

async function fetchCustomerMemorySession(input: {
  customerId: string;
  query?: string;
  threadId?: string | null;
}) {
  const params = new URLSearchParams({
    customerId: input.customerId,
  });

  if (input.query?.trim()) {
    params.set("query", input.query.trim());
  }

  if (input.threadId?.trim()) {
    params.set("threadId", input.threadId.trim());
  }

  const response = await fetch(
    `/api/demos/customer-memory-agent/session?${params.toString()}`
  );

  if (!response.ok) {
    throw new Error(
      (await response.text()) || "Failed to load the customer-memory session."
    );
  }

  return (await response.json()) as CustomerMemorySessionData;
}

async function createCustomerMemoryThread(customerId: string) {
  const response = await fetch("/api/demos/customer-memory-agent/threads", {
    body: JSON.stringify({ customerId }),
    headers: {
      "Content-Type": "application/json",
    },
    method: "POST",
  });

  if (!response.ok) {
    throw new Error(
      (await response.text()) || "Failed to create a customer-memory thread."
    );
  }

  return (await response.json()) as CustomerMemorySessionData;
}

function getDefaultCustomerMemorySelection() {
  return {
    customerId: customerMemoryProfiles[0]?.id ?? "acme-co",
    threadId: null as string | null,
  };
}

function getStoredCustomerMemorySelection() {
  if (typeof window === "undefined") {
    return getDefaultCustomerMemorySelection();
  }

  return {
    customerId:
      window.localStorage.getItem("customer-memory-agent.customer-id") ??
      getDefaultCustomerMemorySelection().customerId,
    threadId:
      window.localStorage.getItem("customer-memory-agent.thread-id") ?? null,
  };
}

function persistCustomerMemorySelection(input: {
  customerId: string;
  threadId: string | null;
}) {
  if (typeof window === "undefined") {
    return;
  }

  window.localStorage.setItem(
    "customer-memory-agent.customer-id",
    input.customerId
  );

  if (input.threadId) {
    window.localStorage.setItem(
      "customer-memory-agent.thread-id",
      input.threadId
    );
    return;
  }

  window.localStorage.removeItem("customer-memory-agent.thread-id");
}

function reportCustomerMemorySessionRefreshError(error: unknown) {
  console.error("Failed to refresh customer-memory session.", error);
}

export interface CustomerMemorySessionController {
  activeThreadId: string | null;
  chatErrorMessage: string | null;
  createThread: () => Promise<void>;
  customerId: string;
  isBusy: boolean;
  isReadonlyAccount: boolean;
  isReady: boolean;
  isSessionLoading: boolean;
  latestPrompt: string;
  messages: UIMessage[];
  refreshSession: (query?: string) => Promise<void>;
  regenerateLastTurn: () => Promise<void>;
  selectCustomer: (customerId: string) => Promise<void>;
  selectThread: (threadId: string) => Promise<void>;
  sendPrompt: (text: string) => Promise<void>;
  session: CustomerMemorySessionData | null;
  sessionErrorMessage: string | null;
  status: ChatStatus;
  stopChat: () => void;
  viewState: ReturnType<typeof buildCustomerMemorySessionViewState>;
}

export function resolveCustomerMemorySessionMessages(input: {
  fallbackMessages?: UIMessage[];
  nextSession: CustomerMemorySessionData;
}) {
  const fallbackMessages = removeEmptyCustomerMemoryAssistantMessages(
    input.fallbackMessages ?? []
  );

  if (fallbackMessages.length <= input.nextSession.messages.length) {
    return input.nextSession.messages;
  }

  return fallbackMessages;
}

export function shouldApplyCustomerMemorySessionRefresh(input: {
  latestRequestId: number;
  requestId: number;
}) {
  return input.requestId === input.latestRequestId;
}

export function useCustomerMemorySession(
  isChatAvailable: boolean
): CustomerMemorySessionController {
  const initialSelection = useMemo(getDefaultCustomerMemorySelection, []);
  const [customerId, setCustomerId] = useState(initialSelection.customerId);
  const [activeThreadId, setActiveThreadId] = useState<string | null>(null);
  const [session, setSession] = useState<CustomerMemorySessionData | null>(
    null
  );
  const [sessionErrorMessage, setSessionErrorMessage] = useState<string | null>(
    null
  );
  const [isSessionLoading, setIsSessionLoading] = useState(true);
  const selectionRef = useRef({
    customerId: initialSelection.customerId,
    threadId: null as string | null,
  });
  const latestRefreshRequestIdRef = useRef(0);
  const activeProfile = useMemo(
    () =>
      customerMemoryProfiles.find((profile) => profile.id === customerId) ??
      customerMemoryProfiles[0],
    [customerId]
  );
  const isReadonlyAccount = activeProfile?.accessMode === "shared_readonly";
  const {
    clearError,
    error,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    setMessages,
    status,
    stop,
  } = useCustomerMemoryChat<UIMessage>({
    createChat: () =>
      new Chat<UIMessage>({
        onFinish: ({ messages }) => {
          const latestPrompt = getLatestCustomerMemoryPrompt(messages);

          refreshSessionRef
            .current(latestPrompt, {
              fallbackMessages: messages,
            })
            .catch(reportCustomerMemorySessionRefreshError);
        },
        transport: new DefaultChatTransport({
          api: "/api/demos/customer-memory-agent",
          prepareSendMessagesRequest({ body, messages }) {
            const threadId = selectionRef.current.threadId;

            if (!threadId) {
              throw new Error(
                "No active customer-memory thread is selected for this request."
              );
            }

            return {
              body: {
                ...body,
                customerId: selectionRef.current.customerId,
                messages,
                threadId,
              },
            };
          },
        }),
      }),
  });
  const latestPrompt = useMemo(
    () => getLatestCustomerMemoryPrompt(messages),
    [messages]
  );
  const refreshSessionRef = useRef<
    (
      query?: string,
      options?: {
        fallbackMessages?: UIMessage[];
      }
    ) => Promise<void>
  >(async () => undefined);

  const applySession = useCallback(
    (
      nextSession: CustomerMemorySessionData,
      options?: { fallbackMessages?: UIMessage[] }
    ) => {
      const resolvedMessages = resolveCustomerMemorySessionMessages({
        fallbackMessages: options?.fallbackMessages,
        nextSession,
      });

      setSession({
        ...nextSession,
        messages: resolvedMessages,
      });
      setCustomerId(nextSession.customer.id);
      setActiveThreadId(nextSession.thread.id);
      selectionRef.current = {
        customerId: nextSession.customer.id,
        threadId: nextSession.thread.id,
      };
      persistCustomerMemorySelection({
        customerId: nextSession.customer.id,
        threadId: nextSession.thread.id,
      });
      setMessages(resolvedMessages);
      clearError();
    },
    [clearError, setMessages]
  );

  const refreshSession = useCallback(
    async (
      query = "",
      options?: {
        fallbackMessages?: UIMessage[];
      }
    ) => {
      const currentSelection = selectionRef.current;
      const requestId = latestRefreshRequestIdRef.current + 1;
      latestRefreshRequestIdRef.current = requestId;
      setIsSessionLoading(true);
      setSessionErrorMessage(null);

      try {
        const nextSession = await fetchCustomerMemorySession({
          customerId: currentSelection.customerId,
          query,
          threadId: currentSelection.threadId,
        });

        if (
          !shouldApplyCustomerMemorySessionRefresh({
            latestRequestId: latestRefreshRequestIdRef.current,
            requestId,
          })
        ) {
          return;
        }

        applySession(nextSession, {
          fallbackMessages: options?.fallbackMessages,
        });
      } catch (sessionError) {
        if (
          !shouldApplyCustomerMemorySessionRefresh({
            latestRequestId: latestRefreshRequestIdRef.current,
            requestId,
          })
        ) {
          return;
        }

        setSessionErrorMessage(
          sessionError instanceof Error
            ? sessionError.message
            : "Failed to refresh the customer-memory session."
        );
      } finally {
        if (
          shouldApplyCustomerMemorySessionRefresh({
            latestRequestId: latestRefreshRequestIdRef.current,
            requestId,
          })
        ) {
          setIsSessionLoading(false);
        }
      }
    },
    [applySession]
  );

  refreshSessionRef.current = refreshSession;

  useEffect(() => {
    const storedSelection = getStoredCustomerMemorySelection();

    selectionRef.current = {
      customerId: storedSelection.customerId,
      threadId: storedSelection.threadId,
    };
    setCustomerId(storedSelection.customerId);
    setActiveThreadId(storedSelection.threadId);
  }, []);

  useEffect(() => {
    if (!isChatAvailable) {
      setIsSessionLoading(false);
      return;
    }

    refreshSession().catch(reportCustomerMemorySessionRefreshError);
  }, [isChatAvailable, refreshSession]);

  async function selectCustomer(nextCustomerId: string) {
    if (isBusy || nextCustomerId === selectionRef.current.customerId) {
      return;
    }

    selectionRef.current = {
      customerId: nextCustomerId,
      threadId: null,
    };
    setCustomerId(nextCustomerId);
    setActiveThreadId(null);
    setSession(null);
    setMessages([]);
    clearError();

    await refreshSession();
  }

  async function selectThread(threadId: string) {
    if (
      isBusy ||
      threadId === selectionRef.current.threadId ||
      !selectionRef.current.customerId
    ) {
      return;
    }

    selectionRef.current = {
      customerId: selectionRef.current.customerId,
      threadId,
    };
    setActiveThreadId(threadId);
    setSession(null);
    setMessages([]);
    clearError();

    await refreshSession();
  }

  async function createThread() {
    if (isBusy || isReadonlyAccount) {
      return;
    }

    setIsSessionLoading(true);
    setSessionErrorMessage(null);
    setSession(null);

    try {
      const nextSession = await createCustomerMemoryThread(
        selectionRef.current.customerId
      );

      applySession(nextSession);
    } catch (threadError) {
      setSessionErrorMessage(
        threadError instanceof Error
          ? threadError.message
          : "Failed to create a new customer-memory thread."
      );
    } finally {
      setIsSessionLoading(false);
    }
  }

  async function sendPrompt(text: string) {
    const trimmedText = text.trim();

    if (!(trimmedText && selectionRef.current.threadId) || isReadonlyAccount) {
      return;
    }

    await sendMessage({ text: trimmedText });
  }

  async function regenerateLastTurn() {
    if (!selectionRef.current.threadId || isReadonlyAccount) {
      return;
    }

    await regenerate();
  }

  return {
    activeThreadId,
    chatErrorMessage: error?.message ?? null,
    customerId,
    isReadonlyAccount,
    isBusy,
    isReady: isChatAvailable && activeThreadId !== null,
    isSessionLoading,
    latestPrompt,
    messages,
    session,
    sessionErrorMessage,
    status,
    viewState: buildCustomerMemorySessionViewState(session),
    createThread,
    regenerateLastTurn,
    refreshSession,
    selectCustomer,
    selectThread,
    sendPrompt,
    stopChat: stop,
  };
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import { desc, eq } from "drizzle-orm";

import { loadCustomerMemoryAgentDatabase } from "./database";
import { getCustomerMemoryAgentEnv } from "./env";
import { createPortableCustomerMemoryCompactionPersistence } from "./portable-store";

export interface CustomerMemoryCompactionRecord {
  createdAt: string;
  id: string;
  messageCount: number;
  summary: string;
  threadId: string;
}

export interface CustomerMemoryCompactionPersistence {
  createCompaction(input: {
    messageCount: number;
    summary: string;
    threadId: string;
  }): Promise<CustomerMemoryCompactionRecord>;
  getLatestCompaction(
    threadId: string
  ): Promise<CustomerMemoryCompactionRecord | null>;
}

interface CustomerMemoryCompactionStoreDependencies {
  persistence?: CustomerMemoryCompactionPersistence;
}

interface CustomerMemoryDatabaseModule {
  customerMemoryCompactions: Awaited<
    ReturnType<typeof loadCustomerMemoryAgentDatabase>
  >["customerMemoryCompactions"];
  database: Awaited<
    ReturnType<typeof loadCustomerMemoryAgentDatabase>
  >["database"];
}

function toIsoString(value: Date | string) {
  return value instanceof Date ? value.toISOString() : value;
}

function normalizeCompactionRecord(record: {
  createdAt: Date | string;
  id: string;
  messageCount: number;
  summary: string;
  threadId: string;
}): CustomerMemoryCompactionRecord {
  return {
    createdAt: toIsoString(record.createdAt),
    id: record.id,
    messageCount: record.messageCount,
    summary: record.summary,
    threadId: record.threadId,
  };
}

function createDatabaseBackedPersistence(): CustomerMemoryCompactionPersistence {
  return {
    async createCompaction(input) {
      const { customerMemoryCompactions, database } =
        await loadCustomerMemoryAgentDatabase();
      const [row] = await database
        .insert(customerMemoryCompactions)
        .values({
          messageCount: input.messageCount,
          summary: input.summary,
          threadId: input.threadId,
        })
        .returning();

      if (!row) {
        throw new Error("Failed to save a customer-memory compaction.");
      }

      return normalizeCompactionRecord(row);
    },
    async getLatestCompaction(threadId) {
      const { customerMemoryCompactions, database } =
        await loadCustomerMemoryAgentDatabase();
      const [row] = await database
        .select()
        .from(customerMemoryCompactions)
        .where(eq(customerMemoryCompactions.threadId, threadId))
        .orderBy(desc(customerMemoryCompactions.createdAt))
        .limit(1);

      return row ? normalizeCompactionRecord(row) : null;
    },
  };
}

export function shouldCompactCustomerMemoryThread(input: {
  messageCount: number;
  threshold: number;
}) {
  return input.messageCount >= input.threshold;
}

export function createCustomerMemoryCompactionStore(
  dependencies: CustomerMemoryCompactionStoreDependencies = {}
) {
  const persistence =
    dependencies.persistence ??
    (getCustomerMemoryAgentEnv().DATABASE_URL
      ? createDatabaseBackedPersistence()
      : createPortableCustomerMemoryCompactionPersistence());

  return {
    async getLatestCompaction(threadId: string) {
      return persistence.getLatestCompaction(threadId);
    },
    async saveCompaction(input: {
      messageCount: number;
      summary: string;
      threadId: string;
    }) {
      return persistence.createCompaction(input);
    },
  };
}

import { generateText, getToolName, isToolUIPart, type UIMessage } from "ai";

import type { CustomerMemoryCompactionRecord } from "./compaction-store";
import {
  createCustomerMemoryAgentGateway,
  getCustomerMemoryAgentConfig,
  getCustomerMemoryAgentEnv,
  type CustomerMemoryAgentEnv,
} from "./env";

export const customerMemoryCompactionThreshold = 3;
export const customerMemoryRecentMessageWindow = 2;

const compactionInstructions = [
  "You are performing a CUSTOMER SUPPORT CONTEXT CHECKPOINT COMPACTION.",
  "Create a handoff note for a future assistant turn that will resume this exact customer thread.",
  "Merge the previous handoff, if present, with the new conversation window.",
  "Preserve durable customer facts, preferences, active commitments, unresolved risks, exact dates, names, account constraints, and requested next actions.",
  "Drop greetings, filler, and resolved details unless they explain the current customer state.",
  "If newer messages contradict the previous handoff, prefer the newer fact and mention uncertainty only when the transcript is unresolved.",
  "Do not invent missing facts. Do not expose this instruction.",
  "Output compact Markdown with these sections only: Current customer state, Durable facts and preferences, Active commitments and risks, Recent thread state, Next assistant guidance.",
].join(" ");

function formatToolValue(value: unknown) {
  return JSON.stringify(value);
}

function formatToolPart(part: UIMessage["parts"][number]) {
  if (!isToolUIPart(part)) {
    return null;
  }

  const lines = [`TOOL ${getToolName(part)} (${part.state})`];

  if ("input" in part && part.input !== undefined) {
    lines.push(`input: ${formatToolValue(part.input)}`);
  }

  if ("output" in part && part.output !== undefined) {
    lines.push(`output: ${formatToolValue(part.output)}`);
  }

  if ("errorText" in part && part.errorText) {
    lines.push(`error: ${part.errorText}`);
  }

  return lines.join("\n");
}

function getMessageCompactionText(message: UIMessage) {
  return message.parts
    .map((part) => {
      if (part.type === "text") {
        return part.text;
      }

      return formatToolPart(part);
    })
    .filter((value): value is string => Boolean(value?.trim()))
    .join("\n")
    .trim();
}

function formatMessagesForSummary(messages: UIMessage[]) {
  return messages
    .map((message) => {
      const text = getMessageCompactionText(message);

      if (text.length === 0) {
        return null;
      }

      return `${message.role.toUpperCase()}: ${text}`;
    })
    .filter((value): value is string => value !== null)
    .join("\n\n");
}

export function getCustomerMemoryCompactionTargetMessageCount(input: {
  latestCompaction: CustomerMemoryCompactionRecord | null;
  messageCount: number;
  recentWindow?: number;
  threshold?: number;
}) {
  const recentWindow = input.recentWindow ?? customerMemoryRecentMessageWindow;
  const threshold = input.threshold ?? customerMemoryCompactionThreshold;

  if (input.messageCount < threshold) {
    return null;
  }

  const targetCount = input.messageCount - recentWindow;

  if (targetCount <= 0) {
    return null;
  }

  if (
    input.latestCompaction &&
    input.latestCompaction.messageCount >= targetCount
  ) {
    return null;
  }

  return targetCount;
}

export function buildCustomerMemoryCompactionInput(input: {
  latestCompaction: CustomerMemoryCompactionRecord | null;
  messages: UIMessage[];
  targetMessageCount: number;
}) {
  const previousMessageCount = input.latestCompaction?.messageCount ?? 0;
  const startIndex = Math.min(previousMessageCount, input.targetMessageCount);
  const messages = input.messages.slice(startIndex, input.targetMessageCount);

  if (messages.length === 0) {
    throw new Error(
      "Cannot compact without newly compactable customer-memory messages."
    );
  }

  return {
    messages,
    previousHandoff: input.latestCompaction?.summary ?? null,
  };
}

export async function generateCustomerMemoryCompactionSummary(
  input: {
    customerLabel: string;
    messages: UIMessage[];
    previousHandoff?: string | null;
  },
  env: CustomerMemoryAgentEnv = getCustomerMemoryAgentEnv()
) {
  const gateway = createCustomerMemoryAgentGateway(env);
  const { chatModel } = getCustomerMemoryAgentConfig(env);
  const messageTranscript = formatMessagesForSummary(input.messages);

  if (messageTranscript.length === 0) {
    throw new Error("Cannot compact an empty customer-memory message window.");
  }

  const result = await generateText({
    model: gateway(chatModel),
    prompt: [
      `Customer account: ${input.customerLabel}`,
      "Previous handoff:",
      input.previousHandoff?.trim() || "No previous handoff exists.",
      "New conversation window:",
      messageTranscript,
    ].join("\n\n"),
    system: compactionInstructions,
  });

  return result.text.trim();
}

import { validateUIMessages, type UIMessage } from "ai";

export const invalidCustomerIdError =
  'Expected a non-empty "customerId" string.';
export const invalidMessagesError =
  'Expected a JSON body with a "messages" array.';
export const invalidThreadIdError = 'Expected a non-empty "threadId" string.';
export const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
export const malformedJsonError = "Expected a valid JSON request body.";

interface CustomerMemoryChatRequestBody {
  customerId?: string;
  messages?: UIMessage[];
  threadId?: string;
}

function readNonEmptyString(value: unknown, errorMessage: string) {
  if (typeof value !== "string" || value.trim().length === 0) {
    throw new Error(errorMessage);
  }

  return value.trim();
}

export async function readCustomerMemoryChatRequest(body: unknown): Promise<{
  customerId: string;
  messages: UIMessage[];
  threadId: string;
}> {
  const { customerId, messages, threadId } = (body ??
    {}) as CustomerMemoryChatRequestBody;

  if (!Array.isArray(messages)) {
    throw new Error(invalidMessagesError);
  }

  const normalizedCustomerId = readNonEmptyString(
    customerId,
    invalidCustomerIdError
  );
  const normalizedThreadId = readNonEmptyString(threadId, invalidThreadIdError);

  try {
    return {
      customerId: normalizedCustomerId,
      messages: await validateUIMessages({ messages }),
      threadId: normalizedThreadId,
    };
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

export function readCustomerMemorySessionQuery(requestUrl: string | URL): {
  customerId: string;
  query: string;
  threadId: string | null;
} {
  const url = requestUrl instanceof URL ? requestUrl : new URL(requestUrl);
  const customerId = readNonEmptyString(
    url.searchParams.get("customerId"),
    invalidCustomerIdError
  );
  const threadId = url.searchParams.get("threadId");

  return {
    customerId,
    query: url.searchParams.get("query")?.trim() ?? "",
    threadId: threadId && threadId.trim().length > 0 ? threadId.trim() : null,
  };
}

export async function readCustomerMemoryThreadCreateRequest(body: unknown) {
  const { customerId } = (body ?? {}) as { customerId?: string };

  return {
    customerId: readNonEmptyString(customerId, invalidCustomerIdError),
  };
}

