function buildEmbeddingContent(memory: CustomerMemoryRecord) {
  return [memory.category, memory.title, memory.content]
    .filter(Boolean)
    .join("\n");
}

const wordPattern = /[a-z0-9]+/g;
const stopWords = new Set([
  "a",
  "and",
  "are",
  "by",
  "for",
  "how",
  "if",
  "is",
  "it",
  "safe",
  "should",
  "that",
  "the",
  "to",
  "today",
  "what",
]);

function tokenizeMemoryText(value: string) {
  return [...value.toLowerCase().matchAll(wordPattern)]
    .map((match) => match[0])
    .filter((token) => !stopWords.has(token));
}

function scoreMemoryForQuery(
  queryTokens: string[],
  memory: CustomerMemoryRecord
) {
  const searchableText = buildEmbeddingContent(memory).toLowerCase();
  const matchedTokens = queryTokens.filter((token) =>
    searchableText.includes(token)
  );

  return matchedTokens.length / Math.max(queryTokens.length, 1);
}

async function findPortableCustomerMemoryMatches(input: {
  customerId: string;
  query: string;
  visitorId: string;
}): Promise<RetrievedCustomerMemory[]> {
  const queryTokens = tokenizeMemoryText(input.query);
  const store = createCustomerMemoryStore();
  const memories = await store.listMemories({
    customerId: input.customerId,
    visitorId: input.visitorId,
  });

  return memories
    .map((memory) => ({
      ...memory,
      similarity: scoreMemoryForQuery(queryTokens, memory),
    }))
    .filter((memory) => memory.similarity > 0)
    .sort((left, right) => right.similarity - left.similarity)
    .slice(0, memoryRecallLimit);
}

async function replaceCustomerMemoryEmbeddings(
  records: CustomerMemoryEmbeddingRecord[],
  loadDatabase: () => Promise<CustomerMemoryRecallDatabaseModule>
) {
  const { customerMemoryEmbeddings, database } = await loadDatabase();

  if (records.length === 0) {
    return;
  }

  await database.transaction(async (transaction) => {
    await transaction.delete(customerMemoryEmbeddings).where(
      inArray(
        customerMemoryEmbeddings.memoryId,
        records.map((record) => record.memoryId)
      )
    );

    await transaction.insert(customerMemoryEmbeddings).values(records);
  });
}

async function findCustomerMemoryMatches(
  input: {
    customerId: string;
    queryEmbedding: number[];
    visitorId: string;
  },
  loadDatabase: () => Promise<CustomerMemoryRecallDatabaseModule>
): Promise<RetrievedCustomerMemory[]> {
  const { customerMemoryEmbeddings, customerMemoryMemories, database } =
    await loadDatabase();
  const similarity = sql<number>`1 - (${cosineDistance(
    customerMemoryEmbeddings.embedding,
    input.queryEmbedding
  )})`;
  const boostedSimilarity = sql<number>`${similarity} + least(${customerMemoryMemories.accessCount} * 0.01, 0.05)`;

  return database
    .select({
      accessCount: customerMemoryMemories.accessCount,
      category: customerMemoryMemories.category,
      content: customerMemoryMemories.content,
      createdAt: customerMemoryMemories.createdAt,
      customerId: customerMemoryMemories.customerId,
      id: customerMemoryMemories.id,
      lastAccessedAt: customerMemoryMemories.lastAccessedAt,
      metadata: customerMemoryMemories.metadata,
      similarity: boostedSimilarity,
      sourceMessageId: customerMemoryMemories.sourceMessageId,
      status: customerMemoryMemories.status,
      threadId: customerMemoryMemories.threadId,
      title: customerMemoryMemories.title,
      updatedAt: customerMemoryMemories.updatedAt,
      visitorId: customerMemoryMemories.visitorId,
    })
    .from(customerMemoryEmbeddings)
    .innerJoin(
      customerMemoryMemories,
      eq(customerMemoryEmbeddings.memoryId, customerMemoryMemories.id)
    )
    .where(
      and(
        eq(customerMemoryMemories.customerId, input.customerId),
        eq(customerMemoryMemories.visitorId, input.visitorId),
        ne(customerMemoryMemories.status, "deleted"),
        gt(similarity, minimumSimilarity)
      )
    )
    .orderBy((table) => desc(table.similarity))
    .limit(memoryRecallLimit)
    .then((rows) =>
      rows.map((row) => ({
        ...row,
        createdAt:
          row.createdAt instanceof Date
            ? row.createdAt.toISOString()
            : row.createdAt,
        lastAccessedAt:
          row.lastAccessedAt instanceof Date
            ? row.lastAccessedAt.toISOString()
            : row.lastAccessedAt,
        metadata: (row.metadata as Record<string, unknown> | null) ?? null,
        status: row.status as CustomerMemoryRecord["status"],
        updatedAt:
          row.updatedAt instanceof Date
            ? row.updatedAt.toISOString()
            : row.updatedAt,
      }))
    );
}

export async function generateCustomerMemoryEmbedding(
  value: string,
  env: CustomerMemoryAgentEnv = getCustomerMemoryAgentEnv()
): Promise<number[]> {
  const gateway = createCustomerMemoryAgentGateway(env);
  const normalizedValue = value.replaceAll("\n", " ").trim();
  const { embedding } = await embed({
    model: gateway.embeddingModel(embeddingModelId),
    value: normalizedValue,
  });

  return embedding;
}

export async function generateCustomerMemoryEmbeddings(
  values: string[],
  env: CustomerMemoryAgentEnv = getCustomerMemoryAgentEnv()
): Promise<number[][]> {
  const gateway = createCustomerMemoryAgentGateway(env);
  const { embeddings } = await embedMany({
    model: gateway.embeddingModel(embeddingModelId),
    values: values.map((value) => value.replaceAll("\n", " ").trim()),
  });

  return embeddings;
}

export async function indexCustomerMemories(
  memories: CustomerMemoryRecord[],
  persistence: Pick<CustomerMemoryEmbeddingPersistence, "replaceEmbeddings">,
  dependencies: Pick<
    CustomerMemoryRecallDependencies,
    "generateEmbeddings"
  > = {}
) {
  if (memories.length === 0) {
    return;
  }

  if (!getCustomerMemoryAgentEnv().DATABASE_URL) {
    return;
  }

  const generateEmbeddings =
    dependencies.generateEmbeddings ?? generateCustomerMemoryEmbeddings;
  const contents = memories.map(buildEmbeddingContent);
  const embeddings = await generateEmbeddings(
    contents,
    getCustomerMemoryAgentEnv()
  );

  await persistence.replaceEmbeddings(
    memories.map((memory, index) => {
      const embedding = embeddings[index];

      if (!embedding) {
        throw new Error(
          `Missing customer-memory embedding ${index} for ${memory.id}.`
        );
      }

      return {
        content: contents[index] ?? memory.content,
        embedding,
        memoryId: memory.id,
      };
    })
  );
}

export const indexCustomerMemoryEntries = indexCustomerMemories;

export async function findRelevantCustomerMemory(
  input: FindRelevantCustomerMemoryInput,
  env: CustomerMemoryAgentEnv = getCustomerMemoryAgentEnv(),
  dependencies: CustomerMemoryRecallDependencies = {}
) {
  const normalizedQuery = input.query.trim();

  if (normalizedQuery.length === 0) {
    return [];
  }

  if (!env.DATABASE_URL && !dependencies.findMatches) {
    const matches = await findPortableCustomerMemoryMatches({
      customerId: input.customerId,
      query: normalizedQuery,
      visitorId: input.visitorId,
    });

    await (
      dependencies.recordSearchHits ??
      (async (memories: RetrievedCustomerMemory[]) => {
        const store = createCustomerMemoryStore();
        await store.markMemoriesAccessed(memories.map((memory) => memory.id));
        await Promise.all(
          memories.map((memory) =>
            store.recordEvent({
              afterContent: memory.content,
              beforeContent: null,
              customerId: memory.customerId,
              memoryId: memory.id,
              metadata: memory.metadata,
              operation: "search_hit",
              reason: `Retrieved for query: ${normalizedQuery}`,
              sourceMessageId: memory.sourceMessageId,
              threadId: memory.threadId,
              visitorId: memory.visitorId,
            })
          )
        );
      })
    )(matches);

    return matches;
  }

  const generateEmbedding =
    dependencies.generateEmbedding ?? generateCustomerMemoryEmbedding;
  const findMatches =
    dependencies.findMatches ??
    ((nextInput: {
      customerId: string;
      queryEmbedding: number[];
      visitorId: string;
    }) =>
      findCustomerMemoryMatches(
        nextInput,
        dependencies.loadDatabase ?? loadCustomerMemoryAgentDatabase
      ));
  const queryEmbedding = await generateEmbedding(normalizedQuery, env);
  const matches = await findMatches({
    customerId: input.customerId,
    queryEmbedding,
    visitorId: input.visitorId,
  });

  await (
    dependencies.recordSearchHits ??
    (async (memories: RetrievedCustomerMemory[]) => {
      const store = createCustomerMemoryStore();
      await store.markMemoriesAccessed(memories.map((memory) => memory.id));
      await Promise.all(
        memories.map((memory) =>
          store.recordEvent({
            afterContent: memory.content,
            beforeContent: null,
            customerId: memory.customerId,
            memoryId: memory.id,
            metadata: memory.metadata,
            operation: "search_hit",
            reason: `Retrieved for query: ${normalizedQuery}`,
            sourceMessageId: memory.sourceMessageId,
            threadId: memory.threadId,
            visitorId: memory.visitorId,
          })
        )
      );
    })
  )(matches);

  return matches;
}

export function createCustomerMemoryEmbeddingPersistence(
  loadDatabase: () => Promise<CustomerMemoryRecallDatabaseModule> = loadCustomerMemoryAgentDatabase
): CustomerMemoryEmbeddingPersistence {
  return {
    findMatches: (input) => findCustomerMemoryMatches(input, loadDatabase),
    replaceEmbeddings: (records) =>
      replaceCustomerMemoryEmbeddings(records, loadDatabase),
  };
}

import { and, desc, eq, inArray, ne, sql } from "drizzle-orm";

import { loadCustomerMemoryAgentDatabase } from "./database";
import { getCustomerMemoryAgentEnv } from "./env";
import { createPortableCustomerMemoryPersistence } from "./portable-store";

export const customerMemoryStatuses = ["active", "updated", "deleted"] as const;
export const customerMemoryOperations = [
  "add",
  "update",
  "delete",
  "search_hit",
  "compact_capture",
  "noop",
] as const;

export type CustomerMemoryStatus = (typeof customerMemoryStatuses)[number];
export type CustomerMemoryOperation = (typeof customerMemoryOperations)[number];
export type CustomerMemoryMetadata = Record<string, unknown> | null;

export interface CustomerMemoryRecord {
  accessCount: number;
  category: string;
  content: string;
  createdAt: string;
  customerId: string;
  id: string;
  lastAccessedAt: string | null;
  metadata: CustomerMemoryMetadata;
  sourceMessageId: string | null;
  status: CustomerMemoryStatus;
  threadId: string | null;
  title: string | null;
  updatedAt: string;
  visitorId: string;
}

export interface CustomerMemoryEventRecord {
  afterContent: string | null;
  beforeContent: string | null;
  createdAt: string;
  customerId: string;
  id: string;
  memoryId: string | null;
  metadata: CustomerMemoryMetadata;
  operation: CustomerMemoryOperation;
  reason: string | null;
  sourceMessageId: string | null;
  threadId: string | null;
  visitorId: string;
}

export interface CustomerMemoryMemoryPersistence {
  createMemory(input: {
    category: string;
    content: string;
    customerId: string;
    metadata?: CustomerMemoryMetadata;
    reason?: string | null;
    sourceMessageId?: string | null;
    threadId?: string | null;
    title?: string | null;
    visitorId: string;
  }): Promise<CustomerMemoryRecord>;
  deleteMemory(input: {
    memoryId: string;
    reason?: string | null;
    sourceMessageId?: string | null;
  }): Promise<void>;
  listEventsForCustomer(input: {
    customerId: string;
    visitorId: string;
  }): Promise<CustomerMemoryEventRecord[]>;
  listVisibleMemoriesForCustomer(input: {
    customerId: string;
    visitorId: string;
  }): Promise<CustomerMemoryRecord[]>;
  markMemoryAccessed(memoryIds: string[]): Promise<void>;
  recordEvent(input: {
    afterContent?: string | null;
    beforeContent?: string | null;
    customerId: string;
    memoryId?: string | null;
    metadata?: CustomerMemoryMetadata;
    operation: CustomerMemoryOperation;
    reason?: string | null;
    sourceMessageId?: string | null;
    threadId?: string | null;
    visitorId: string;
  }): Promise<CustomerMemoryEventRecord>;
  updateMemory(input: {
    category?: string;
    content: string;
    memoryId: string;
    metadata?: CustomerMemoryMetadata;
    reason?: string | null;
    sourceMessageId?: string | null;
    title?: string | null;
  }): Promise<CustomerMemoryRecord>;
}

interface CustomerMemoryStoreDependencies {
  persistence?: CustomerMemoryMemoryPersistence;
}

interface CustomerMemoryDatabaseModule {
  customerMemoryEvents: Awaited<
    ReturnType<typeof loadCustomerMemoryAgentDatabase>
  >["customerMemoryEvents"];
  customerMemoryMemories: Awaited<
    ReturnType<typeof loadCustomerMemoryAgentDatabase>
  >["customerMemoryMemories"];
  database: Awaited<
    ReturnType<typeof loadCustomerMemoryAgentDatabase>
  >["database"];
}

function toIsoString(value: Date | string | null) {
  if (value === null) {
    return null;
  }

  return value instanceof Date ? value.toISOString() : value;
}

function normalizeStatus(value: string): CustomerMemoryStatus {
  if (customerMemoryStatuses.includes(value as CustomerMemoryStatus)) {
    return value as CustomerMemoryStatus;
  }

  throw new Error(`Unknown customer-memory status: ${value}`);
}

function normalizeOperation(value: string): CustomerMemoryOperation {
  if (customerMemoryOperations.includes(value as CustomerMemoryOperation)) {
    return value as CustomerMemoryOperation;
  }

  throw new Error(`Unknown customer-memory operation: ${value}`);
}

function normalizeMetadata(value: unknown): CustomerMemoryMetadata {
  if (value === null || value === undefined) {
    return null;
  }

  if (typeof value !== "object" || Array.isArray(value)) {
    throw new Error("Customer-memory metadata must be a JSON object.");
  }

  return value as Record<string, unknown>;
}

function normalizeMemoryRecord(record: {
  accessCount: number;
  category: string;
  content: string;
  createdAt: Date | string;
  customerId: string;
  id: string;
  lastAccessedAt: Date | string | null;
  metadata: unknown;
  sourceMessageId: string | null;
  status: string;
  threadId: string | null;
  title: string | null;
  updatedAt: Date | string;
  visitorId: string;
}): CustomerMemoryRecord {
  return {
    accessCount: record.accessCount,
    category: record.category,
    content: record.content,
    createdAt: toIsoString(record.createdAt) ?? "",
    customerId: record.customerId,
    id: record.id,
    lastAccessedAt: toIsoString(record.lastAccessedAt),
    metadata: normalizeMetadata(record.metadata),
    sourceMessageId: record.sourceMessageId,
    status: normalizeStatus(record.status),
    threadId: record.threadId,
    title: record.title,
    updatedAt: toIsoString(record.updatedAt) ?? "",
    visitorId: record.visitorId,
  };
}

function normalizeEventRecord(record: {
  afterContent: string | null;
  beforeContent: string | null;
  createdAt: Date | string;
  customerId: string;
  id: string;
  memoryId: string | null;
  metadata: unknown;
  operation: string;
  reason: string | null;
  sourceMessageId: string | null;
  threadId: string | null;
  visitorId: string;
}): CustomerMemoryEventRecord {
  return {
    afterContent: record.afterContent,
    beforeContent: record.beforeContent,
    createdAt: toIsoString(record.createdAt) ?? "",
    customerId: record.customerId,
    id: record.id,
    memoryId: record.memoryId,
    metadata: normalizeMetadata(record.metadata),
    operation: normalizeOperation(record.operation),
    reason: record.reason,
    sourceMessageId: record.sourceMessageId,
    threadId: record.threadId,
    visitorId: record.visitorId,
  };
}

async function insertMemoryEvent(
  input: Parameters<CustomerMemoryMemoryPersistence["recordEvent"]>[0],
  databaseModule: CustomerMemoryDatabaseModule
) {
  const [row] = await databaseModule.database
    .insert(databaseModule.customerMemoryEvents)
    .values({
      afterContent: input.afterContent ?? null,
      beforeContent: input.beforeContent ?? null,
      customerId: input.customerId,
      memoryId: input.memoryId ?? null,
      metadata: input.metadata ?? null,
      operation: input.operation,
      reason: input.reason ?? null,
      sourceMessageId: input.sourceMessageId ?? null,
      threadId: input.threadId ?? null,
      visitorId: input.visitorId,
    })
    .returning();

  if (!row) {
    throw new Error("Failed to save a customer-memory event.");
  }

  return normalizeEventRecord(row);
}

async function getMemoryForMutation(
  memoryId: string,
  databaseModule: CustomerMemoryDatabaseModule
) {
  const [row] = await databaseModule.database
    .select()
    .from(databaseModule.customerMemoryMemories)
    .where(
      and(
        eq(databaseModule.customerMemoryMemories.id, memoryId),
        ne(databaseModule.customerMemoryMemories.status, "deleted")
      )
    )
    .limit(1);

  if (!row) {
    throw new Error(`No active customer memory found for ${memoryId}.`);
  }

  return row;
}

function createDatabaseBackedPersistence(): CustomerMemoryMemoryPersistence {
  return {
    async createMemory(input) {
      const databaseModule = await loadCustomerMemoryAgentDatabase();
      let savedMemory: CustomerMemoryRecord | null = null;

      await databaseModule.database.transaction(async (transaction) => {
        const [row] = await transaction
          .insert(databaseModule.customerMemoryMemories)
          .values({
            category: input.category,
            content: input.content,
            customerId: input.customerId,
            metadata: input.metadata ?? null,
            sourceMessageId: input.sourceMessageId ?? null,
            threadId: input.threadId ?? null,
            title: input.title ?? null,
            visitorId: input.visitorId,
          })
          .returning();

        if (!row) {
          throw new Error("Failed to save a customer memory.");
        }

        await insertMemoryEvent(
          {
            afterContent: row.content,
            beforeContent: null,
            customerId: row.customerId,
            memoryId: row.id,
            metadata: normalizeMetadata(row.metadata),
            operation: "add",
            reason: input.reason ?? null,
            sourceMessageId: row.sourceMessageId,
            threadId: row.threadId,
            visitorId: row.visitorId,
          },
          {
            ...databaseModule,
            database: transaction as unknown as typeof databaseModule.database,
          }
        );

        savedMemory = normalizeMemoryRecord(row);
      });

      if (!savedMemory) {
        throw new Error("Failed to save a customer memory.");
      }

      return savedMemory;
    },
    async deleteMemory(input) {
      const databaseModule = await loadCustomerMemoryAgentDatabase();

      await databaseModule.database.transaction(async (transaction) => {
        const transactionModule = {
          ...databaseModule,
          database: transaction as unknown as typeof databaseModule.database,
        };
        const current = await getMemoryForMutation(
          input.memoryId,
          transactionModule
        );
        await transaction
          .update(databaseModule.customerMemoryMemories)
          .set({ status: "deleted", updatedAt: new Date() })
          .where(eq(databaseModule.customerMemoryMemories.id, input.memoryId));

        await insertMemoryEvent(
          {
            afterContent: null,
            beforeContent: current.content,
            customerId: current.customerId,
            memoryId: current.id,
            metadata: normalizeMetadata(current.metadata),
            operation: "delete",
            reason: input.reason ?? null,
            sourceMessageId: input.sourceMessageId ?? current.sourceMessageId,
            threadId: current.threadId,
            visitorId: current.visitorId,
          },
          transactionModule
        );
      });
    },
    async listEventsForCustomer(input) {
      const { customerMemoryEvents, database } =
        await loadCustomerMemoryAgentDatabase();
      const rows = await database
        .select()
        .from(customerMemoryEvents)
        .where(
          and(
            eq(customerMemoryEvents.customerId, input.customerId),
            eq(customerMemoryEvents.visitorId, input.visitorId)
          )
        )
        .orderBy(desc(customerMemoryEvents.createdAt));

      return rows.map(normalizeEventRecord);
    },
    async listVisibleMemoriesForCustomer(input) {
      const { customerMemoryMemories, database } =
        await loadCustomerMemoryAgentDatabase();
      const rows = await database
        .select()
        .from(customerMemoryMemories)
        .where(
          and(
            eq(customerMemoryMemories.customerId, input.customerId),
            eq(customerMemoryMemories.visitorId, input.visitorId),
            ne(customerMemoryMemories.status, "deleted")
          )
        )
        .orderBy(desc(customerMemoryMemories.updatedAt));

      return rows.map(normalizeMemoryRecord);
    },
    async markMemoryAccessed(memoryIds) {
      if (memoryIds.length === 0) {
        return;
      }

      const { customerMemoryMemories, database } =
        await loadCustomerMemoryAgentDatabase();
      await database
        .update(customerMemoryMemories)
        .set({
          accessCount: sql`${customerMemoryMemories.accessCount} + 1`,
          lastAccessedAt: new Date(),
        })
        .where(
          and(
            inArray(customerMemoryMemories.id, memoryIds),
            ne(customerMemoryMemories.status, "deleted")
          )
        );
    },
    async recordEvent(input) {
      return insertMemoryEvent(input, await loadCustomerMemoryAgentDatabase());
    },
    async updateMemory(input) {
      const databaseModule = await loadCustomerMemoryAgentDatabase();
      let savedMemory: CustomerMemoryRecord | null = null;

      await databaseModule.database.transaction(async (transaction) => {
        const transactionModule = {
          ...databaseModule,
          database: transaction as unknown as typeof databaseModule.database,
        };
        const current = await getMemoryForMutation(
          input.memoryId,
          transactionModule
        );
        const [row] = await transaction
          .update(databaseModule.customerMemoryMemories)
          .set({
            category: input.category ?? current.category,
            content: input.content,
            metadata: input.metadata ?? current.metadata,
            sourceMessageId: input.sourceMessageId ?? current.sourceMessageId,
            status: "updated",
            title: input.title ?? current.title,
            updatedAt: new Date(),
          })
          .where(eq(databaseModule.customerMemoryMemories.id, input.memoryId))
          .returning();

        if (!row) {
          throw new Error(
            `Failed to update customer memory ${input.memoryId}.`
          );
        }

        await insertMemoryEvent(
          {
            afterContent: row.content,
            beforeContent: current.content,
            customerId: row.customerId,
            memoryId: row.id,
            metadata: normalizeMetadata(row.metadata),
            operation: "update",
            reason: input.reason ?? null,
            sourceMessageId: row.sourceMessageId,
            threadId: row.threadId,
            visitorId: row.visitorId,
          },
          transactionModule
        );

        savedMemory = normalizeMemoryRecord(row);
      });

      if (!savedMemory) {
        throw new Error(`Failed to update customer memory ${input.memoryId}.`);
      }

      return savedMemory;
    },
  };
}

export function createCustomerMemoryStore(
  dependencies: CustomerMemoryStoreDependencies = {}
) {
  const persistence =
    dependencies.persistence ??
    (getCustomerMemoryAgentEnv().DATABASE_URL
      ? createDatabaseBackedPersistence()
      : createPortableCustomerMemoryPersistence());

  return {
    addMemory: persistence.createMemory,
    deleteMemory: persistence.deleteMemory,
    listEvents: persistence.listEventsForCustomer,
    listMemories: persistence.listVisibleMemoriesForCustomer,
    markMemoriesAccessed: persistence.markMemoryAccessed,
    recordEvent: persistence.recordEvent,
    updateMemory: persistence.updateMemory,
  };
}

import type { UIMessage } from "ai";

import type {
  CustomerMemoryCompactionPersistence,
  CustomerMemoryCompactionRecord,
} from "./compaction-store";
import type {
  CustomerMemoryEventRecord,
  CustomerMemoryMemoryPersistence,
  CustomerMemoryMetadata,
  CustomerMemoryRecord,
} from "./memory-store";
import type {
  CustomerMemoryThreadPersistence,
  CustomerMemoryThreadRecord,
  CustomerMemoryThreadSummary,
  PersistedCustomerMemoryMessage,
} from "./thread-store";

interface PortableCustomerMemoryState {
  compactions: CustomerMemoryCompactionRecord[];
  events: CustomerMemoryEventRecord[];
  memories: Map<string, CustomerMemoryRecord>;
  messagesByThreadId: Map<string, PersistedCustomerMemoryMessage[]>;
  threads: Map<string, CustomerMemoryThreadRecord>;
}

const globalStore = globalThis as typeof globalThis & {
  __customerMemoryPortableStore?: PortableCustomerMemoryState;
};

function getPortableState(): PortableCustomerMemoryState {
  globalStore.__customerMemoryPortableStore ??= {
    compactions: [],
    events: [],
    memories: new Map(),
    messagesByThreadId: new Map(),
    threads: new Map(),
  };

  return globalStore.__customerMemoryPortableStore;
}

function createPortableId(prefix: string) {
  return `${prefix}-${crypto.randomUUID()}`;
}

function nowIsoString() {
  return new Date().toISOString();
}

function cloneRecord<T>(value: T): T {
  return structuredClone(value);
}

function normalizeMetadata(
  metadata: CustomerMemoryMetadata | undefined
): CustomerMemoryMetadata {
  return metadata ?? null;
}

function createMemoryEventRecord(input: {
  afterContent?: string | null;
  beforeContent?: string | null;
  customerId: string;
  memoryId?: string | null;
  metadata?: CustomerMemoryMetadata;
  operation: CustomerMemoryEventRecord["operation"];
  reason?: string | null;
  sourceMessageId?: string | null;
  threadId?: string | null;
  visitorId: string;
}): CustomerMemoryEventRecord {
  return {
    afterContent: input.afterContent ?? null,
    beforeContent: input.beforeContent ?? null,
    createdAt: nowIsoString(),
    customerId: input.customerId,
    id: createPortableId("cm-event"),
    memoryId: input.memoryId ?? null,
    metadata: normalizeMetadata(input.metadata),
    operation: input.operation,
    reason: input.reason ?? null,
    sourceMessageId: input.sourceMessageId ?? null,
    threadId: input.threadId ?? null,
    visitorId: input.visitorId,
  };
}

function pushMemoryEvent(
  state: PortableCustomerMemoryState,
  input: Parameters<CustomerMemoryMemoryPersistence["recordEvent"]>[0]
) {
  const event = createMemoryEventRecord(input);
  state.events.push(event);
  return cloneRecord(event);
}

export function createPortableCustomerMemoryThreadPersistence(): CustomerMemoryThreadPersistence {
  const state = getPortableState();

  return {
    async createThread(input) {
      const timestamp = nowIsoString();
      const thread: CustomerMemoryThreadRecord = {
        createdAt: timestamp,
        customerId: input.customerId,
        id: createPortableId("cm-thread"),
        title: input.title ?? null,
        updatedAt: timestamp,
        visitorId: input.visitorId,
      };

      state.threads.set(thread.id, thread);
      state.messagesByThreadId.set(thread.id, []);

      return cloneRecord(thread);
    },
    async findThreadById(threadId) {
      const thread = state.threads.get(threadId);
      return thread ? cloneRecord(thread) : null;
    },
    async loadThreadMessages(threadId) {
      return cloneRecord(state.messagesByThreadId.get(threadId) ?? []);
    },
    async listThreadsForCustomer(input) {
      return [...state.threads.values()]
        .filter(
          (thread) =>
            thread.customerId === input.customerId &&
            thread.visitorId === input.visitorId
        )
        .map(
          (thread): CustomerMemoryThreadSummary => ({
            ...thread,
            messageCount: state.messagesByThreadId.get(thread.id)?.length ?? 0,
          })
        )
        .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
        .map(cloneRecord);
    },
    async replaceThreadMessages(input) {
      const thread = state.threads.get(input.threadId);

      if (!thread) {
        throw new Error(`No customer-memory thread found for ${input.threadId}.`);
      }

      const timestamp = nowIsoString();
      state.messagesByThreadId.set(
        input.threadId,
        input.messages.map((message, messageIndex) => ({
          createdAt: timestamp,
          id: createPortableId("cm-message"),
          message: cloneRecord(message),
          messageId: message.id,
          messageIndex,
          role: message.role,
          threadId: input.threadId,
        }))
      );
      state.threads.set(input.threadId, { ...thread, updatedAt: timestamp });
    },
  };
}

export function createPortableCustomerMemoryPersistence(): CustomerMemoryMemoryPersistence {
  const state = getPortableState();

  return {
    async createMemory(input) {
      const timestamp = nowIsoString();
      const memory: CustomerMemoryRecord = {
        accessCount: 0,
        category: input.category,
        content: input.content,
        createdAt: timestamp,
        customerId: input.customerId,
        id: createPortableId("cm-memory"),
        lastAccessedAt: null,
        metadata: normalizeMetadata(input.metadata),
        sourceMessageId: input.sourceMessageId ?? null,
        status: "active",
        threadId: input.threadId ?? null,
        title: input.title ?? null,
        updatedAt: timestamp,
        visitorId: input.visitorId,
      };

      state.memories.set(memory.id, memory);
      pushMemoryEvent(state, {
        afterContent: memory.content,
        beforeContent: null,
        customerId: memory.customerId,
        memoryId: memory.id,
        metadata: memory.metadata,
        operation: "add",
        reason: input.reason ?? null,
        sourceMessageId: memory.sourceMessageId,
        threadId: memory.threadId,
        visitorId: memory.visitorId,
      });

      return cloneRecord(memory);
    },
    async deleteMemory(input) {
      const current = state.memories.get(input.memoryId);

      if (!current || current.status === "deleted") {
        throw new Error(`No active customer memory found for ${input.memoryId}.`);
      }

      const next = {
        ...current,
        status: "deleted" as const,
        updatedAt: nowIsoString(),
      };
      state.memories.set(input.memoryId, next);
      pushMemoryEvent(state, {
        afterContent: null,
        beforeContent: current.content,
        customerId: current.customerId,
        memoryId: current.id,
        metadata: current.metadata,
        operation: "delete",
        reason: input.reason ?? null,
        sourceMessageId: input.sourceMessageId ?? current.sourceMessageId,
        threadId: current.threadId,
        visitorId: current.visitorId,
      });
    },
    async listEventsForCustomer(input) {
      return state.events
        .filter(
          (event) =>
            event.customerId === input.customerId &&
            event.visitorId === input.visitorId
        )
        .sort((left, right) => right.createdAt.localeCompare(left.createdAt))
        .map(cloneRecord);
    },
    async listVisibleMemoriesForCustomer(input) {
      return [...state.memories.values()]
        .filter(
          (memory) =>
            memory.customerId === input.customerId &&
            memory.visitorId === input.visitorId &&
            memory.status !== "deleted"
        )
        .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
        .map(cloneRecord);
    },
    async markMemoryAccessed(memoryIds) {
      const timestamp = nowIsoString();

      for (const memoryId of memoryIds) {
        const memory = state.memories.get(memoryId);

        if (!memory || memory.status === "deleted") {
          continue;
        }

        state.memories.set(memoryId, {
          ...memory,
          accessCount: memory.accessCount + 1,
          lastAccessedAt: timestamp,
        });
      }
    },
    async recordEvent(input) {
      return pushMemoryEvent(state, input);
    },
    async updateMemory(input) {
      const current = state.memories.get(input.memoryId);

      if (!current || current.status === "deleted") {
        throw new Error(`No active customer memory found for ${input.memoryId}.`);
      }

      const next: CustomerMemoryRecord = {
        ...current,
        category: input.category ?? current.category,
        content: input.content,
        metadata: normalizeMetadata(input.metadata ?? current.metadata),
        sourceMessageId: input.sourceMessageId ?? current.sourceMessageId,
        status: "updated",
        title: input.title ?? current.title,
        updatedAt: nowIsoString(),
      };

      state.memories.set(input.memoryId, next);
      pushMemoryEvent(state, {
        afterContent: next.content,
        beforeContent: current.content,
        customerId: next.customerId,
        memoryId: next.id,
        metadata: next.metadata,
        operation: "update",
        reason: input.reason ?? null,
        sourceMessageId: next.sourceMessageId,
        threadId: next.threadId,
        visitorId: next.visitorId,
      });

      return cloneRecord(next);
    },
  };
}

export function createPortableCustomerMemoryCompactionPersistence(): CustomerMemoryCompactionPersistence {
  const state = getPortableState();

  return {
    async createCompaction(input) {
      const compaction: CustomerMemoryCompactionRecord = {
        createdAt: nowIsoString(),
        id: createPortableId("cm-compaction"),
        messageCount: input.messageCount,
        summary: input.summary,
        threadId: input.threadId,
      };

      state.compactions.push(compaction);

      return cloneRecord(compaction);
    },
    async getLatestCompaction(threadId) {
      const compaction = state.compactions
        .filter((candidate) => candidate.threadId === threadId)
        .sort((left, right) => right.createdAt.localeCompare(left.createdAt))[0];

      return compaction ? cloneRecord(compaction) : null;
    },
  };
}

